import sysfrom pathlib import Pathimport jsonimport reimport joblibimport numpy as npimport pandas as pdimport pyarrow.parquet as pqfrom gensim.models import Word2Vecfrom sklearn.linear_model import LogisticRegressionfrom sklearn.metrics import (    accuracy_score,    classification_report,    confusion_matrix,    f1_score,)from sklearn.preprocessing import StandardScalerPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import (    PROCESSED_DATA_DIR,    EMBEDDINGS_DIR,    BASELINE_MODELS_DIR,    REPORTS_DIR,    TABLE_DIR,    INTERIM_DATA_DIR,)DATASET_TAG = "large_lite"EXPERIMENT_TAG = "mean_scaled_v1"TEXT_COL = "full_text"LABEL_COL = "label_5d"MIN_TOKEN_LEN = 2BATCH_SIZE = 128def simple_tokenize(text: str):    text = str(text).lower()    tokens = re.findall(r"[a-zA-Z0-9]+", text)    tokens = [tok for tok in tokens if len(tok) >= MIN_TOKEN_LEN]    return tokensdef get_split_paths():    return {        "train": PROCESSED_DATA_DIR / "train_doc_5d_large_lite.parquet",        "validation": PROCESSED_DATA_DIR / "validation_doc_5d_large_lite.parquet",        "test": PROCESSED_DATA_DIR / "test_doc_5d_large_lite.parquet",    }def load_word2vec():    model_path = EMBEDDINGS_DIR / f"word2vec_{DATASET_TAG}.model"    if not model_path.exists():        raise FileNotFoundError(f"Word2Vec model not found: {model_path}")    return Word2Vec.load(str(model_path))def basic_data_check(split_name: str, parquet_path: Path):    table = pq.read_table(parquet_path, columns=[TEXT_COL, LABEL_COL])    df = table.to_pandas()    print(f"\n--- {split_name.upper()} ---")    print("Shape:", df.shape)    print("Label distribution:")    print(df[LABEL_COL].value_counts(dropna=False).sort_index())    print(df[[TEXT_COL, LABEL_COL]].head(2))def document_to_vector_mean(tokens, w2v_model):    vectors = []    for tok in tokens:        if tok in w2v_model.wv:            vectors.append(w2v_model.wv[tok])    if len(vectors) == 0:        return np.zeros(w2v_model.vector_size, dtype=np.float32)    return np.mean(vectors, axis=0).astype(np.float32)def build_embedding_matrix_from_parquet(parquet_path: Path, w2v_model, split_name: str):    parquet_file = pq.ParquetFile(parquet_path)    X_parts = []    y_parts = []    coverage = []    n_docs = 0    print(f"\nBuilding mean embeddings for {split_name} in batches...")    for batch_idx, batch in enumerate(        parquet_file.iter_batches(batch_size=BATCH_SIZE, columns=[TEXT_COL, LABEL_COL]),        start=1,    ):        batch_df = batch.to_pandas()        X_batch = []        y_batch = []        for _, row in batch_df.iterrows():            tokens = simple_tokenize(row[TEXT_COL])            vec = document_to_vector_mean(tokens, w2v_model)            X_batch.append(vec)            y_batch.append(int(row[LABEL_COL]))            if len(tokens) == 0:                coverage.append(0.0)            else:                in_vocab = sum(tok in w2v_model.wv for tok in tokens)                coverage.append(in_vocab / len(tokens))            n_docs += 1        X_parts.append(np.vstack(X_batch).astype(np.float32))        y_parts.append(np.array(y_batch, dtype=np.int32))        if batch_idx % 20 == 0:            print(                f"[{split_name}] processed batches: {batch_idx} | "                f"documents: {n_docs:,}"            )    X = np.vstack(X_parts).astype(np.float32)    y = np.concatenate(y_parts)    print(f"{split_name} embedding shape: {X.shape}")    return X, y, coveragedef train_classifier(X_train, y_train, X_val, y_val):    candidates = [        {"C": 0.001},        {"C": 0.003},        {"C": 0.01},        {"C": 0.03},        {"C": 0.05},        {"C": 0.1},    ]    scaler = StandardScaler()    X_train_scaled = scaler.fit_transform(X_train)    X_val_scaled = scaler.transform(X_val)    best_model = None    best_result = None    all_results = []    for i, cfg in enumerate(candidates, start=1):        print(f"\nTraining candidate {i}: {cfg}")        clf = LogisticRegression(            C=cfg["C"],            max_iter=2000,            random_state=42,        )        clf.fit(X_train_scaled, y_train)        val_pred = clf.predict(X_val_scaled)        acc = accuracy_score(y_val, val_pred)        f1 = f1_score(y_val, val_pred)        result = {            "candidate_id": i,            "C": cfg["C"],            "val_accuracy": acc,            "val_f1": f1,        }        all_results.append(result)        print(f"Validation Accuracy: {acc:.4f}")        print(f"Validation F1:       {f1:.4f}")        if best_result is None or f1 > best_result["val_f1"]:            best_result = result            best_model = clf    return scaler, best_model, best_result, pd.DataFrame(all_results)def evaluate_on_test(scaler, model, X_test, y_test):    X_test_scaled = scaler.transform(X_test)    test_pred = model.predict(X_test_scaled)    test_acc = accuracy_score(y_test, test_pred)    test_f1 = f1_score(y_test, test_pred)    cm = confusion_matrix(y_test, test_pred)    clf_report = classification_report(y_test, test_pred, output_dict=True)    print("\n=== TEST PERFORMANCE ===")    print(f"Test Accuracy: {test_acc:.4f}")    print(f"Test F1:       {test_f1:.4f}")    print("Confusion Matrix:")    print(cm)    return {        "test_accuracy": test_acc,        "test_f1": test_f1,        "confusion_matrix": cm.tolist(),        "classification_report": clf_report,    }def save_outputs(    scaler,    clf,    best_result,    validation_results_df,    test_results,    X_train,    X_val,    X_test,    train_coverage,    val_coverage,    test_coverage,):    BASELINE_MODELS_DIR.mkdir(parents=True, exist_ok=True)    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    TABLE_DIR.mkdir(parents=True, exist_ok=True)    INTERIM_DATA_DIR.mkdir(parents=True, exist_ok=True)    scaler_path = BASELINE_MODELS_DIR / f"word2vec_scaler_{DATASET_TAG}_{EXPERIMENT_TAG}.joblib"    model_path = BASELINE_MODELS_DIR / f"word2vec_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}.joblib"    report_path = REPORTS_DIR / f"word2vec_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}_results.json"    val_table_path = TABLE_DIR / f"word2vec_logistic_{DATASET_TAG}_{EXPERIMENT_TAG}_validation_results.csv"    train_embed_path = INTERIM_DATA_DIR / f"train_doc_embedding_word2vec_{DATASET_TAG}_{EXPERIMENT_TAG}.npy"    val_embed_path = INTERIM_DATA_DIR / f"validation_doc_embedding_word2vec_{DATASET_TAG}_{EXPERIMENT_TAG}.npy"    test_embed_path = INTERIM_DATA_DIR / f"test_doc_embedding_word2vec_{DATASET_TAG}_{EXPERIMENT_TAG}.npy"    np.save(train_embed_path, X_train)    np.save(val_embed_path, X_val)    np.save(test_embed_path, X_test)    joblib.dump(scaler, scaler_path)    joblib.dump(clf, model_path)    validation_results_df.to_csv(val_table_path, index=False)    payload = {        "dataset_tag": DATASET_TAG,        "experiment_tag": EXPERIMENT_TAG,        "best_validation_result": best_result,        "test_results": test_results,        "avg_train_token_coverage": float(np.mean(train_coverage)),        "avg_validation_token_coverage": float(np.mean(val_coverage)),        "avg_test_token_coverage": float(np.mean(test_coverage)),    }    with open(report_path, "w", encoding="utf-8") as f:        json.dump(payload, f, indent=2)    print("\nSaved outputs:")    print(scaler_path)    print(model_path)    print(report_path)    print(val_table_path)    print(train_embed_path)    print(val_embed_path)    print(test_embed_path)def main():    split_paths = get_split_paths()    basic_data_check("train", split_paths["train"])    basic_data_check("validation", split_paths["validation"])    basic_data_check("test", split_paths["test"])    print("\nLoading Word2Vec model...")    w2v_model = load_word2vec()    print(f"Word2Vec vector size: {w2v_model.vector_size}")    print(f"Word2Vec vocab size:  {len(w2v_model.wv.key_to_index):,}")    X_train, y_train, train_coverage = build_embedding_matrix_from_parquet(        split_paths["train"], w2v_model, "train"    )    X_val, y_val, val_coverage = build_embedding_matrix_from_parquet(        split_paths["validation"], w2v_model, "validation"    )    X_test, y_test, test_coverage = build_embedding_matrix_from_parquet(        split_paths["test"], w2v_model, "test"    )    print("\nAverage token coverage:")    print(f"Train:      {np.mean(train_coverage):.4f}")    print(f"Validation: {np.mean(val_coverage):.4f}")    print(f"Test:       {np.mean(test_coverage):.4f}")    print("\nTraining StandardScaler + Logistic Regression on mean-pooled document embeddings...")    scaler, best_model, best_result, validation_results_df = train_classifier(        X_train, y_train, X_val, y_val    )    print("\nBest validation configuration:")    print(best_result)    test_results = evaluate_on_test(scaler, best_model, X_test, y_test)    save_outputs(        scaler,        best_model,        best_result,        validation_results_df,        test_results,        X_train,        X_val,        X_test,        train_coverage,        val_coverage,        test_coverage,    )    print("\nDone.")if __name__ == "__main__":    main()